export type Cell = [number, number];

const MIN_NEIGHBORS_TO_SURVIVE = 2;
const MAX_NEIGHBORS_TO_SURVIVE = 3;

function isNeighbor(a: Cell, b: Cell): boolean {
  const [ax, ay] = a;
  const [bx, by] = b;
  return Math.max(Math.abs(ax - bx), Math.abs(ay - by)) === 1;
}

function survives(cell: Cell, cells: Cell[]): boolean {
  const count = cells.filter((other) => isNeighbor(cell, other)).length;
  return count >= MIN_NEIGHBORS_TO_SURVIVE && count <= MAX_NEIGHBORS_TO_SURVIVE;
}

export function nextGeneration(cells: Cell[]): Cell[] {
  return cells.filter((cell) => survives(cell, cells));
}

